# Section 5: Conversation practice (chapterIds 620–662). Eighteen natural lines each: English, Assamese, transliteration.
from assamese_lesson_helpers import ch, r, block_table


def _c(cid: int, title: str, content: str, intro: str, rows: list) -> dict:
    return ch(cid, title, content, intro, blocks=[block_table("Conversation", rows)])


def add_chapters_620_662(out: list) -> None:
    """Curated Assamese conversation lines for each topic (no generic filler)."""
    # ----- 620–629 -----
    out.append(
        _c(
            620,
            "Diwali Festival in Assamese",
            "Greetings, lights, sweets, and wishes during Deepavali and Kali Puja in Assamese-speaking homes.",
            "শুভ দীপাৱলী — common festive wish when lamps are lit.",
            [
                r("Happy Diwali to you and your family.", "আপোনাৰ আৰু আপোনাৰ পৰিয়াললৈ শুভ দীপাৱলীৰ শুভেচ্ছা জানাইছোঁ।", "Apunar aru apunar poriyalloi shubho dipawolir shubhechcha janaisu."),
                r("Happy Kali Puja — may the goddess bless your home.", "শুভ কালী পূজা; দেৱী মাতৃয়ে আপোনাৰ ঘৰখন শান্তি আৰু সমৃদ্ধিৰে পূৰ্ণ কৰক।", "Shubho Kali Puja; dewi matriye apunar ghorkhon xanti aru somriddhire purṇ koruk."),
                r("We light earthen lamps on the courtyard and balcony.", "আমি উঠন আৰু বাৰান্দাত মাটিৰ সকি জ্বলাই সন্ধিয়া উজ্জ্বল কৰোঁ।", "Ami uṭhon aru barandat matir saki zlai xondhiya ujjol koru."),
                r("Please come in — we have just offered prayers and shared prasad.", "অনুগ্ৰহ কৰি ভিতৰলৈ আহক; আমি এতিয়েই পূজা শেষ কৰি প্ৰসাদ বিতৰণ কৰিছোঁ।", "Onugrah kori bhitôrlôi aho; ami etiye puja xex kori prosad bitoron korisu."),
                r("These ladoos and coconut sweets are all made at home with care.", "এই লাড়ু আৰু নাৰিকলৰ মিঠাইবোৰ ঘৰতে সাৱধানে বনোৱা হৈছে।", "Ei laṛu aru narikolor mithaibor ghorte xawodhane bonua hoise."),
                r("If children burst crackers, we keep a bucket of water nearby for safety.", "সৰুৰাই পটকা ফুটালে আমি নিৰাপত্তাৰ বাবে পানীৰ বাল্টি কাষতে ৰাখোঁ।", "Soruṛai poṭka futale ami nirapottar babe panir balti kaxhôte rakhu."),
                r("Wear cotton clothes and avoid loose sleeves near open flames.", "সুতিৰ কাপোৰ পিন্ধক আৰু জুইৰ ওচৰত ঢিলা হাতখনা এৰি দিয়ক।", "Sutir kapur pindhok aru zuiro ochorot dhila hatokhona eri diyak."),
                r("The whole lane glows with rows of lamps — it feels like the city is smiling.", "গোটেই গলিটো সকিৰ শাৰীৰে জ্বলি উঠিছে; চহৰখন যেন হাঁহি থকা অনুভৱ হয়।", "Gotei golito sakir share zoli uthishe; sohorkhon jeno hãhi thoka ônubhôb hoẏ."),
                r("May your year ahead be bright like this festival of lights.", "আগন্তুক বছৰখন এই পৰ্বৰ দৰেই উজ্জ্বল হওক আপোনাৰ বাবে।", "Agontuk bosorkhon ei porbor dorei ujjol hok apunar babe."),
                r("Thank you for inviting us; we rarely get such a warm evening together.", "আমন্ত্ৰণ দিয়াৰ বাবে ধন্যবাদ; ইমান গৰম সন্ধিয়া একেলগে পোৱাটো বিৰল।", "Amontron diyar babe dhonnobad; iman gorom xondhiya kelge puaṭo birol."),
                r("We exchange good wishes with neighbours and share a little mishti.", "প্ৰতিবেশীৰ সৈতে শুভেচ্ছা বিনিময় কৰোঁ আৰু অলপ মিঠাই ভাগ-বতৰা কৰোঁ।", "Protibexir xote shubhechcha binimoy koru aru olop mithai bhag-botora koru."),
                r("I bought new clothes for my parents so they could join the puja comfortably.", "মই মা-দেউতাৰ বাবে নতুন জামা কিনিছোঁ যাতে তেওঁলোকে আৰামে পূজাত অংশ গ্ৰহণ কৰিব পাৰে।", "Moi ma-deutar babe nôtun jama kinisu jate teoluke arame pujat onxo grohon koribe pare."),
                r("The evening arati with drums and bells still echoes in my ears.", "ঢোল আৰু ঘণ্টাৰ সৈতে কৰা সন্ধিয়াৰ আৰতিটোৱে এতিয়াও মোৰ কাণত বাজি আছে।", "Dhol aru ghoṇṭar xote kora xondhiyar aratiṭowe etiyao mur kanot baji ase."),
                r("Good night — rest well after all the walking and visiting.", "শুভ ৰাতি; ইমান খোজ আৰু ঘূৰি ফুৰাৰ পিছত ভালকৈ বিশ্ৰাম ল’ব।", "Xubh rati; iman khôj aru ghuri phurar pisot bhal koi bixram lobo."),
                r("See you tomorrow morning at the community hall for the children's programme.", "কাইলৈ ৰাতিপুৱা সমাজৰ কাৰ্যালয়ত শিশুৰ অনুষ্ঠানত পুনৰ দেখা হ’ব।", "Kailoi ratipuwa xomajor karyaloyot xixur anusthanot punor dekha hobo."),
                r("Happy holidays — travel safely if you are going to your village.", "শুভ ছুটি; গাঁলৈ যোৱা হ’লে নিৰাপদে যাব যেন লক্ষ্য ৰাখিব।", "Xubh chuṭi; gãlôi zua hole nirapode zaba jeno lokhyo rakhib."),
                r("Let us remember to turn off extra decorative lights when we sleep.", "ঘুমোৱাৰ সময়ত অতিৰিক্ত সজ্জাৰ বতি নিভোৱাটো মনত ৰাখিব লাগিব।", "Ghumuar xomoyot otirikto xojjar boti nibhuaṭo monot rakhib lagibo."),
                r("This festival reminds us that kindness spreads faster than any spark.", "এই পৰ্বটোৱে মনত পেলাই দিয়ে যে দয়া যিকোনো ঠৰৰ প্ৰতি স্পৰ্শতকৈ দ্ৰুতে বিয়পে।", "Ei porboṭowe monot pelai diye je doẏa zikonu thoror prôtisphorxhotkoi drute biyope."),
            ],
        )
    )
    out.append(
        _c(
            621,
            "Simple Sentences in Assamese – Introduction/Salutation",
            "Introducing yourself, asking names, and polite greetings in formal and informal Assamese.",
            "নমস্কাৰ — neutral greeting; তুমি/আপুনি by age and respect.",
            [
                r("Hello — I am glad we could meet on such a pleasant evening.", "নমস্কাৰ; ইমান ভাল সন্ধিয়াত আমাৰ দেখা হোৱাটো মোৰ বাবে আনন্দৰ কথা।", "Nomoskar; iman bhal xondhiyat amar dekha huwaṭo mor babe anondor kotha."),
                r("Good morning — I hope you slept well after your journey.", "সুপ্ৰভাত; আপোনাৰ যাত্ৰাৰ পিছত ভালকৈ ঘুমাইছে নেকি বুলি আশা কৰোঁ।", "Suprobhat; apunar jotrār pisot bhal koi ghumaise neki buli axa koru."),
                r("Good evening — the breeze from the Brahmaputra feels wonderful today.", "শুভ সন্ধ্যা; আজি ব্ৰহ্মপুত্ৰৰ পৰা অহা বতাহটো অতি মনোৰম।", "Xubh xondhya; aji bromoputror para oha botahoṭo oti monorom."),
                r("My name is Priyanka, and I work with a small publishing house in Guwahati.", "মোৰ নাম প্ৰিয়ংকা; মই গুৱাহাটীৰ এটা সৰু প্ৰকাশন ঘৰত কাম কৰোঁ।", "Mor nam Priyoṅka; moi Guwahatir eta soru prokaxon ghorot kam koru."),
                r("May I know your good name and what brings you to this neighbourhood?", "আপোনাৰ মৰ্যাদাসূচক নাম আৰু এই মহলালৈ কি কাৰণে আহিছে জানিব পাৰিমনে?", "Apunar moryadasuchok nam aru ei moholalôi ki karone ahishe janibo parimone?"),
                r("I am truly pleased to meet someone who speaks Assamese so clearly.", "অসমীয়া এনেকৈ স্পষ্টকৈ কোৱা মানুহৰ সৈতে দেখা পাই মই সঁচাকৈয়ে আনন্দিত।", "Oxoriya enekoi sposhṭokoi kua manuhar xote dekha pai moi sochakoiye anondito."),
                r("Where are you from originally, and how long have you lived in this city?", "আপুনি মূলত ক’ৰ পৰা আৰু এই চহৰত কিমান দিন ধৰি আছে?", "Apuni mulot kor para aru ei sohort kim din dhori ase?"),
                r("I am from Jorhat, but my grandparents still farm near the tea gardens.", "মই যোৰহাটৰ, কিন্তু মোৰ আই-টাই-দেউতাৰ এতিয়াও চাহবাগিচাৰ কাষতে খেতি কৰে।", "Moi Jorhotor, kintu mor ai-tai-deutar etiyao sahbagichar kaxhôte kheti kore."),
                r("This is my colleague Rakesh — we often travel together for work.", "এই মোৰ সহকৰ্মী ৰাকেশ; আমি কামৰ বাবে বহু সময় একেলগে ভ্ৰমণ কৰোঁ।", "Ei mor xohokormi Rakesh; ami kamor babe bohu xomoy kelge bhromon koru."),
                r("Welcome to our home — please wipe your feet and make yourself comfortable.", "আমাৰ ঘৰলৈ স্বাগতম; অনুগ্ৰহ কৰি ভৰি পৰিষ্কাৰ কৰি আৰামে বহক।", "Amar ghorloi swagotom; onugrah kori bhori poriskar kori arame bohok."),
                r("Would you like some tea with milk or do you prefer lemon tea?", "আপুনি গাখীৰৰ চাহ নে লেবুৰ চাহ পচন্দ কৰে?", "Apuni gakhiror chah ne lebur chah posondo kore?"),
                r("Thank you very much for taking time out of your busy schedule.", "আপোনাৰ ব্যস্ত সময়সূচীৰ পৰা সময় উলিয়াই দিয়াৰ বাবে অশেষ ধন্যবাদ।", "Apunar best xomoysuchir para xomoy uliai diyar babe oxex dhonnobad."),
                r("You have been very kind to explain the route in such detail.", "পথটো ইমান বিৱৰণে বুজাই দিয়াৰ বাবে আপুনি বৰ দয়ালু।", "Pothoṭo iman biworne bujai diyar babe apuni bor doẏalu."),
                r("I hope we can meet again before you leave for your next assignment.", "আপুনি পৰৱৰ্তী কামলৈ যোৱাৰ আগতে আমি আকৌ দেখা পাওঁ।", "Apuni pororxoti kamlôi zuar agote ami akou dekha pau."),
                r("Goodbye for now — my mother is calling me to help in the kitchen.", "এতিয়াৰ বাবে বিদায়; মাকে ৰান্ধনিঘৰত সহায় লাগে বুলি মাতিছে।", "Etiyar babe bidaẏ; make randhonighorot xohaẏ lage buli matise."),
                r("Take care on your way back — the roads are slippery after the rain.", "ঘূৰি যোৱাৰ পথত সাৱধান; বৰষুণৰ পিছত ৰাস্তা পিচলী।", "Ghuri zuar pothot xawodhon; boroxunor pisot rasta picholi."),
                r("Have a peaceful day — may your meetings go smoothly.", "শান্তিপূৰ্ণ দিন কটাওক; আপোনাৰ সকলো বৈঠক মিলিব।", "Xantipurn din koṭauk; apunar xokolô boithok milibo."),
                r("I look forward to hearing more about your research next week.", "আগন্তুক সপ্তাহত আপোনাৰ গৱেষণাৰ বিষয়ে অধিক শুনিবলৈ অপেক্ষাত আছোঁ।", "Agontuk xoptahot apunar goxesṇar bixoẏe ôdhik xuniboloi ôpekkhat asu."),
            ],
        )
    )
    out.append(
        _c(
            622,
            "Simple Assamese Sentences – Time Related",
            "Asking and telling the time, days, and schedules in natural Assamese.",
            "কিমান বাজিছে? — What time is it?",
            [
                r("Could you tell me what time it is — my phone battery just died?", "কিমান বাজিছে জনাব পাৰিবনে; মোৰ ফোনৰ বেটাৰি এতিয়েই শেষ হ’ল?", "Kiman bajise janibo paribone; mor phoner betari etiye xex hol?"),
                r("It is exactly five o'clock; the office will close in an hour.", "ঠিক পাঁচটা বাজিছে; এঘণ্টাৰ ভিতৰতে কাৰ্যালয় বন্ধ হ’ব।", "Ṭhik pãchoṭa bajise; eghoṇṭar bhitôrote karyaloy bondho hobo."),
                r("It is half past eight — we should leave soon if we want to catch the bus.", "সাঢ়ে আঠটা বাজিছে; বাছ ধৰিব লাগিলে সোনকালে ওলাই যাব লাগিব।", "Saṛe aṭhoṭa bajise; bax dhoribo lagele sonkole olai zabo lagibo."),
                r("I usually wake up at six and listen to the radio for ten minutes.", "মই সাধাৰণতে ছয়টাত উঠোঁ আৰু দহ মিনিট ৰেডিঅ’ শুনোঁ।", "Moi xadharaṇote xoyṭat uthu aru doh miniṭ reḍio xunu."),
                r("Breakfast is ready at eight, but today we waited for the milk delivery.", "আটটাত জলপান সাজে, কিন্তু আজি গাখীৰ আনিবলৈ অপেক্ষা কৰিলোঁ।", "Aṭoṭat jolpon saje, kintu aji gakhir aniboloi ôpekkha korilu."),
                r("The meeting with the head teacher is fixed at ten in the morning.", "মুখ্য শিক্ষকৰ সৈতে বৈঠক ৰাতিপুৱা দহটাত নিৰ্ধাৰিত।", "Mukhyo xikkhokor xote boithok ratipuwa dohotat nirdharito."),
                r("I work from nine to five on weekdays, but sometimes I stay late for reports.", "কৰ্মদিনত নয়টাৰ পৰা পাঁচটালৈ কাম কৰোঁ, কিন্তু কেতিয়াবা প্ৰতিবেদনৰ বাবে পলমকৈ থাকোঁ।", "Kormodinot noyṭar para pãchoṭaloi kam koru, kintu ketiyaba prôtibedonor babe polomkoi thaku."),
                r("Today is Monday, so the weekly market will be crowded near the river.", "আজি সোমবাৰ, গতিকে সাপ্তাহিক বজাৰ নদীৰ কাষত ভিৰ হ’ব।", "Aji sombar, gotike xoptahik bajar nodir kaxhot bhir hobo."),
                r("Tomorrow is Tuesday — I promised to take my aunt to the doctor.", "কাইলৈ মঙ্গলবাৰ; মই মাহীক চিকিৎসকৰ ওচৰলৈ লৈ যাবলৈ প্ৰতিশ্ৰুতি দিছোঁ।", "Kailoi moṅgolbar; moi mahik xikitxokor ochorloi loi zaboloi protixruti disu."),
                r("I will come tomorrow morning with the documents you asked for.", "আপুনি বিচৰা কাগজপত্ৰ লৈ কাইলৈ ৰাতিপুৱা আহিম।", "Apuni bisora kagojpotro loi kailoi ratipuwa ahim."),
                r("We can leave in an hour once this heavy rain slows down a little.", "এই প্ৰবল বৰষুণ অলপ মন্থা হ’লে আমি এঘণ্টাৰ ভিতৰত ওলাই যাম।", "Ei probol boroxun olop montha hole ami eghoṇṭar bhitôrot olai zam."),
                r("The medicine shop opens at ten, so let us not hurry through breakfast.", "ঔষধৰ দোকান দহটাত খোলে, গতিকে জলপান শেষ কৰি লওঁ।", "Ousodhor dokān dohotat khule, gotike jolpon xex kori lou."),
                r("Sorry, I am late — the bridge was closed for repair without notice.", "ক্ষমা কৰিব; পোহৰতে মই দেৰি কৰিলোঁ; মেৰামতৰ বাবে দলঙ অকস্মাৎ বন্ধ আছিল।", "Khoma korib; pohorte moi deri korilu; meramotor babe dôloṅ okoxmat bondho asil."),
                r("Please wait five more minutes; my sister is bringing the umbrella.", "আৰু পাঁচ মিনিট অপেক্ষা কৰক; ভনীয়ে ছাতি আনি আছে।", "Aru pãch miniṭ ôpekkha korok; bhoniye chati ani ase."),
                r("What time do you usually go to bed after finishing your homework?", "ঘৰুৱা কাম শেষ কৰি সাধাৰণতে কিমান বজাত শোৱে?", "Goruwa kam xex kori xadharaṇote kiman bojat xuwe?"),
                r("I usually sleep by eleven, but during exams I study until midnight.", "সাধাৰণতে এগাৰটাত শোৱোঁ, কিন্তু পৰীক্ষাৰ সময়ত আধাৰাতৈ পঢ়োঁ।", "Xadharaṇote egaroṭat xuwu, kintu porikhar xomoyot adharatoi poṛu."),
                r("See you at four near the bookshop — we can walk to the river together.", "চাৰিটাত কিতাপৰ দোকানৰ কাষত দেখা হ’ব; নদীলৈ একেলগে খোজ মাৰিম।", "Sāriṭat kitapor dokānor kaxhot dekha hobo; nodiloi kelge khôj marim."),
                r("Have a pleasant afternoon — I will call you after my dentist appointment.", "অপৰাহ্ণটো ভাল কটুক; দন্ত বিশেষজ্ঞৰ পিছত মই ফোন কৰিম।", "Oporahṇoṭo bhal koṭuk; dontô bixexjñor pisot moi phon korim."),
            ],
        )
    )
    out.append(
        _c(
            623,
            "Simple Assamese Sentences – Where/Place Related",
            "Asking directions, landmarks, and describing locations in towns and villages.",
            "ক’ত — where; বাওঁ/সোঁ — left/right.",
            [
                r("Could you tell me where the railway station is from this crossing?", "এই মোৰৰ পৰা ৰেলৱে ষ্টেচন ক’ত; কিমান খোজ দূৰ?", "Ei moror para relwe sṭechen kot; kiman khôj dur?"),
                r("How far is the airport — should I take a taxi or a shared van?", "বিমানবন্দৰ কিমান দূৰ; টেক্সি নে শ্বেয়াৰিং ভেন ল’ব লাগে?", "Bimānôbondor kiman dur; ṭeksi ne sheyaring bhen lobô lage?"),
                r("Go straight until you see the old banyan tree near the pond.", "পোখুৰীৰ ওচৰৰ পুৰণি বটগছখন দেখা নোপোৱালৈকৈ সোজা যাওক।", "Pokhurir ochoror puroni boṭogoskhon dekha nopoalôike soja zaok."),
                r("At the traffic signal turn left and walk slowly on the footpath.", "ট্ৰাফিক ছিগনেলত বাওঁফালে মুৰক আৰু ফুটপাথত ধীৰে খোজ কঢ়ক।", "Traphik signelot bawphalê muruk aru futpathot dhire khôj koṛok."),
                r("After the bridge turn right towards the big hospital building.", "দলঙ পাৰ হোৱাৰ পিছত সোঁফালে মুৰি ডাঙৰ চিকিৎসালয়টোৰ ফালে যাওক।", "Dôloṅ par huwar pisot soñphale muri daṅor xikitxaloyṭor phale zaok."),
                r("The post office is just beside the cooperative bank — you cannot miss it.", "ডাকঘৰ সহযোগিতা বেংকৰ কাষতে; আপুনি নেদেখাকৈ থাকিব নোৱাৰে।", "Ḍakghor xohojogita beṅkôr kaxhôte; apuni nedekhaiko thakibo nware."),
                r("The hotel faces the park — rooms on the upper floors are quieter.", "হোটেলখন উদ্যানৰ সন্মুখত; ওপৰৰ তলাৰ কোঠাবোৰ শান্ত।", "Hoṭelkhon udyônôr sonmukhot; ôporor talar koṭhabor xanto."),
                r("Is there safe parking for two-wheelers near the market gate?", "বজাৰৰ গেটৰ কাষত দুইচকীয়া গাড়ীৰ বাবে নিৰাপদ পাৰ্কিং আছেনে?", "Bajaror getor kaxhot duichokiya gaṛir babe nirapod pārkiṃ achene?"),
                r("I think I am lost — this lane looks different on the map I saved.", "মই পথ হেৰালোঁ যেন লাগে; মই সঞ্চয় কৰা মানচিত্ৰত এই গলিটো বেলেগ দেখা যায়।", "Moi poth heralu jene lage; moi sonzoy kora mancitrot ei golito beleg dekha jaẏ."),
                r("Could you show me on the phone map where the museum actually is?", "মোবাইলৰ মানচিত্ৰত জাদুঘৰটো ক’ত আছে চাই দিব পাৰিবনে?", "Mobailor mancitrot jadughoṭo kot ase sai dibo paribone?"),
                r("Which city bus goes to Fancy Bazar — does it stop near the river?", "কোনখন চহৰীয়া বাছ ফেন্সী বজাৰলৈ যায়; নদীৰ কাষত থামেনে?", "Konkhon sohoriya bax Fensi Bajarloi jaẏ; nodir kaxhot thamene?"),
                r("Please get down at the next stop — I will ring the bell for you.", "পৰৱৰ্তী ষ্টপত নমক; মই আপোনাৰ বাবে ঘণ্টি বজাম।", "Pororxoti sṭopot nomok; moi apunar babe ghoṇṭi bzam."),
                r("The washroom is on the first floor — take the stairs on your left.", "প্ৰথম তলাত শৌচালয়; বাওঁফালৰ সিঢ়ী ব্যৱহাৰ কৰক।", "Prothom tolāt xoucaloy; bawphalor shiṛi bẽbohar korok."),
                r("I have lived in this ward for years — the tea stall on the corner is famous.", "বহু বছৰ ধৰি এই ৱাৰ্ডত আছোঁ; মোৰৰ চাহৰ দোকানখন বিখ্যাত।", "Bohu bosor dhori ei wārḍot asu; moror sahor dokānkhon bikhjat."),
                r("There is a good vegetarian restaurant two streets away if you are hungry.", "যদি ভোক লাগে, দুটা গলি পাৰ হ’লে ভাল নিৰামিষ ৰেষ্টুৰেণ্ট পাব।", "Jodi bhook lage, duṭa goli par hole bhal niramiṣ resṭurenṭ pab."),
                r("Where can I hire a reliable taxi late at night without paying too much?", "ৰাতিপুৱাৰ পিছত বিশ্বাসযোগ্য টেক্সি ক’ত পাম; অতিৰিক্ত ভাড়া নিদিব বিচাৰোঁ।", "Ratipuwar pisot bixaxjogyo ṭeksi kot pam; otirikto bhaṛa nidibo bisaru."),
                r("The main road is under repair — follow the diversion signs carefully.", "মুখ্য ৰাস্তা মেৰামতিত; ডাইভাৰচনৰ চিহ্নবোৰ সাৱধানে মানি চলক।", "Mukhyo rasta meramotit; ḍaibarxonor sihnobor xawodhane mani colok."),
                r("Thank you for patiently explaining the way — you saved my interview.", "পথটো ধৈৰ্য ধৰি বুজাই দিয়াৰ বাবে ধন্যবাদ; আপুনিয়ে মোৰ সাক্ষাৎকাৰ ৰক্ষা কৰিলে।", "Pothoṭo dhoirjo dhori bujai diyar babe dhonnobad; apuniye mor xakhyatkār rokxa korile."),
            ],
        )
    )
    out.append(
        _c(
            624,
            "Simple Assamese Sentences – In Hotel",
            "Booking rooms, keys, checkout, and polite requests at a hotel reception.",
            "ৰিচেপচন — reception; চেকআউট — checkout.",
            [
                r("Good evening — I have a reservation under the name Baruah for two nights.", "শুভ সন্ধ্যা; দুৰাতিৰ বাবে বৰুৱা নামত বুকিং আছে।", "Xubh xondhya; duratir babe Boruah namot bukiṃ ase."),
                r("We need a quiet double room with an attached bathroom if possible.", "সম্ভৱ হ’লে সংলগ্ন গাখীৰীয়া ঘৰৰ সৈতে শান্ত ডাবল ৰুম লাগে।", "Xombhôw hole songlogno gakhiriya ghoror xote xanto ḍabol rum lage."),
                r("What is the tariff per night including breakfast and Wi‑Fi?", "ৰাতি প্ৰতি ভাড়া কিমান; জলপান আৰু ৱাই-ফাই অন্তৰ্ভুক্ত নেকি?", "Rati proti bhaṛa kiman; jolpon aru wai-phai ôntorbhukta neki?"),
                r("Is breakfast served on the terrace or only in the dining hall?", "জলপান টেৰেচত নে কেৱল ভোজনালয়তে দিয়া হয়?", "Jolpon ṭerechat ne kebol bhojonaloyote diya hoẏ?"),
                r("May we see the room before we pay — we prefer a floor with less noise?", "টকা দিয়াৰ আগতে ৰুমখন চাব পাৰিমনে; কম শব্দৰ তলা বিচাৰোঁ।", "Toka diyar agote rumkhon sabo parimone; kom xôrdor tola bisaru."),
                r("The air conditioner is humming but not cooling — could someone check it?", "এচিৰ আৱাজ হৈছে ঠাণ্ডা নহয়; কোনোবাই চাই দিবনে?", "Esir awaz hoise thaṇḍa nohoẏ; konoubai sai dibone?"),
                r("Please send two extra towels and a blanket — the night feels colder than usual.", "আৰু দুটা তৱাল আৰু কম্বল পঠাই দিয়ক; ৰাতিটো সাধাৰণতকৈ ঠাণ্ডা।", "Aru duṭa towal aru kombol poṭhai diyak; ratiṭo xadharaṇotkoi thaṇḍa."),
                r("What is the password for the guest Wi‑Fi — my video call keeps dropping?", "অতিথি ৱাই-ফাইৰ পাছৱৰ্ড কি; মোৰ ভিডিঅ’ কল কাটি যায়?", "Otithi wai-phair paswôrḍ ki; mor bideo kol kaṭi jaẏ?"),
                r("At what time is checkout tomorrow — can we leave our bags for a few hours?", "কাইলৈ চেকআউট কিমান বজাত; কেইঘণ্টামান বেগ ৰাখিব পাৰিমনে?", "Kailoi chekaut kiman bojat; keighoṇṭaman beg rakhibo parimone?"),
                r("Please keep our luggage in the cloakroom while we visit the temple.", "আমি মন্দিৰলৈ গৈ থাকোঁতে সামগ্ৰী ভঁৰাল ঘৰত ৰাখক।", "Ami mondilôi goi thakute xamgori bhoral ghorot rakhok."),
                r("We would like to extend one more night because my flight was postponed.", "মোৰ ফ্লাইট পলম হোৱাৰ বাবে আৰু এৰাতি থাকিব লাগে।", "Mor phlaiṭ polom huwar babe aru erati thakibo lage."),
                r("Can I pay with card — do you add a service charge automatically?", "কাৰ্ডেৰে দিব পাৰিমনে; সেৱা মাচুল স্বয়ংক্ৰিয়ভাৱে যোগ হয় নেকি?", "Kārḍere dibo parimone; sewa masul xoyongkriyobhabe zog hoẏ neki?"),
                r("Please prepare the bill with GST break-up so we can claim reimbursement.", "জিএচটি বিভাজন সহ বিলটো সাজাই দিয়ক যাতে ৰিইম্বাৰ্ছ দাবী কৰিব পাৰোঁ।", "Jiesti bibhazon xoh bilṭo sazai diyak jate rimbars dabi koribo paru."),
                r("Could you call a prepaid taxi to the airport at five tomorrow morning?", "কাইলৈ ৰাতিপুৱা পাঁচটাত বিমানবন্দৰলৈ প্ৰিপেইড টেক্সি মাতিব পাৰিবনে?", "Kailoi ratipuwa pãchoṭat bimānôbondôrloi priped ṭeksi matibo paribone?"),
                r("Is hot water available around the clock in the bathroom?", "গাঁঠনি ঘৰত চৌবিশ ঘণ্টা গৰম পানী পোৱা যায় নেকি?", "Gãṭhoni ghorot saubix ghonta gorom pani pua jaẏ neki?"),
                r("The room is spotless — your housekeeping team deserves praise.", "ৰুমখন একেবাৰে পৰিষ্কাৰ; ঘৰ চোৱা দলটোৱে প্রশংসা পাব লাগে।", "Rumkhon ekewāre poriskar; ghor sua doloṭowe proxoṅxa pab lage."),
                r("Thank you — we truly enjoyed the hospitality and the local snacks.", "ধন্যবাদ; আপোনালোকৰ আতিথেয়তা আৰু স্থানীয় নাস্তা বৰ ভাল লাগিল।", "Dhonnobad; apunalokor otitheẏota aru sthaniya nasta bor bhal lagil."),
                r("Goodbye — we will recommend this hotel to friends visiting Assam.", "বিদায়; অসমলৈ অহা বন্ধুবৰ্গক এই হোটেলৰ কথা ক’ম।", "Bidaẏ; Oxomloi oha bondhuborgok ei hoṭelor kotha kom."),
            ],
        )
    )
    out.append(
        _c(
            625,
            "Simple Assamese sentences – Weather related",
            "Talking about heat, rain, cold, and seasons in Assamese.",
            "বৰষুণ হৈছে — it is raining.",
            [
                r("How does the weather feel today — is the humidity higher than usual?", "আজি বতৰ কেনেকুৱা; সাধাৰণতকৈ আৰ্দ্ৰতা বেছি নেকি?", "Aji botor kenuwa; xadharaṇotkoi ardrotā beshi neki?"),
                r("It is scorching outside — I think we should carry water for the children.", "বাহিৰত বৰ গৰম; সৰুৰাৰ বাবে পানী লৈ যোৱাটো ভাল হ’ব।", "Bahirot bor gorom; soruṛar babe pani loi zuwaṭo bhal hobo."),
                r("Today feels chilly — the wind from the hills brought a sudden drop.", "আজি ঠাণ্ডা অনুভৱ; পাহাৰৰ পৰা অকস্মাৎ বতাহ আহিছে।", "Aji thaṇḍa ônubhôw; paharor para okoxmat botah ahishe."),
                r("It has been raining steadily since dawn — the fields look emerald green.", "পুৱাৰ পৰা একে ধৰে বৰষুণ; পথাৰবোৰ মেৰাল সেউজ দেখা যায়।", "Puwar para ekedhore boroxun; patharbor merāl xeuj dekha jaẏ."),
                r("Take this umbrella — the forecast says showers may return after noon.", "এই ছাতি লওক; অপৰাহ্ণৰ পিছত পুনৰ বৰষুণ হ’ব বুলি খবৰ।", "Ei chati louk; oporahṇor pisot punor boroxun hobo buli khabor."),
                r("The sky is overcast with dark clouds — farmers are hoping for steady rain.", "আকাশটো মেঘেৰে ঢাকি আছে; খেতিয়কসকলে একনাগাৰে বৰষুণৰ আশা কৰিছে।", "Akaxoṭo meghere dhaki ase; khetiyoksôle eknagare boroxunor axa korishe."),
                r("A squall may cross the valley — let us not stand under the lone tree.", "ভূঞালী এটা উপত্যকা পাৰ হ’ব পাৰে; একক গছৰ তলত নুঠিব।", "Bhuyali eta upotoka par hobo pare; ekok gosor tolot nuṭhib."),
                r("I love winter mornings in Tezpur when the mist hugs the tea bushes.", "তেজপুৰৰ শীতৰ ৰাতিপুৱা মোৰ বৰ ভাল; কুঁৱলীয়ে চাহ গছ ঢাকে।", "Tejpuror xitor ratipuwa mor bor bhal; kuwaliye sah gos dhake."),
                r("Summer afternoons can be exhausting — please rest if you feel dizzy.", "গ্ৰীষ্মৰ অপৰাহ্ণ ক্লান্তিকৰ; মূৰ ঘূৰিলে অলপ বিশ্ৰাম ল’ব।", "Grismor oporahṇ klantikor; mur ghurile olop bixram lobo."),
                r("The ceiling fan is enough for now — open the window after sunset.", "এতিয়াৰ বাবে পাখাটো যথেষ্ট; সূৰ্যাস্তৰ পিছত খিড়িকি খোলক।", "Etiyar babe pakoṭo jotheshṭ; surjastor pisot khiriki khulok."),
                r("Humidity makes the air feel heavy — cotton clothes help a lot.", "আৰ্দ্ৰতাৰ বাবে বতাহ ভাৰী লাগে; সুতিৰ কাপোৰে বহু সহায় কৰে।", "Ardrotar babe botah bhari lage; sutir kapure bohu xohaẏ kore."),
                r("Wear a light jacket — the temperature may fall sharply after eight.", "পাতল জেকেট পিন্ধক; আঠটাৰ পিছত তাপমাত্ৰা হঠাত কমি পৰিব পাৰে।", "Patol jeket pindhok; aṭoṭar pisot tapmaṭra hoṭhat komi poribe pare."),
                r("The low-lying roads are waterlogged — drive only if the engine is high.", "নিম্ন ৰাস্তাবোৰ জলমগ্ন; ইঞ্জিন উচ্চ হ’লে মাথোঁ চলোৱা।", "Nimno rastabor jolmogno; injin ucco hole maṭhou slua."),
                r("The sky cleared suddenly — children ran out to fly kites on the terrace.", "আকাশ অকস্মাৎ পৰিষ্কাৰ; সৰুৰাই টেৰেচত ঘুৰি উৰোৱালৈ দৌৰি গ’ল।", "Akax okoxmat poriskar; soruṛai ṭerechat ghuri uroalôi douri gol."),
                r("Evenings are pleasant when the river breeze carries the smell of flowers.", "নদীৰ বতাহ ফুলৰ গন্ধ লৈ আহিলে সন্ধিয়া অতি মনোৰম হয়।", "Nodir botah phulor gondh loi ahile xondhiya oti monorom hoẏ."),
                r("Do not go out in the midday sun — dehydration can hit very quickly.", "মধ্যাহ্নৰ ৰ’দত বাহিৰ নাযাব; পানীৰ অভাৱত অসুস্থ হ’ব পাৰে।", "Mojjahnor rodôt bahir najab; panir ôbhawot ôsustho hobo pare."),
                r("The weather bulletin warns of thunderstorms in the western districts.", "পাশ্চিম জিলাবোৰত বজ্ৰপাতৰ আশংকা বুলি বতৰৰ বুলেটিনে জনাইছে।", "Paxcim zilaborot bojropator axoṅka buli botor bulentine janaise."),
                r("Stay safe in rough weather — text me when you reach home.", "খৰাপ বতৰত নিৰাপদে থাকক; ঘৰ পাই মেচেজ কৰিব।", "Kharap botorot nirapode thakok; ghor pai mesej korib."),
            ],
        )
    )
